head.script:
scwin.arrRtnVal = [];

scwin.onpageload = function() {
    scwin.params = $c.data.getParameter();
};

scwin.onUdcCompleted = function() {
    if (scwin.params != null && !$c.gus.cfIsNull(scwin.params["oldCust"])) {
        ed_oldCust.setValue(scwin.params["oldCust"]);
    }
    if (scwin.params != null && !$c.gus.cfIsNull(scwin.params["oldCustnm"])) {
        txt_oldCustnm.setValue(scwin.params["oldCustnm"]);
    }
};

scwin.f_FieldClear = function() {
    if (scwin.bOptDisableTF == "T") return;
    $c.gus.cfInitObjects(tbl_search, null);
    ed_newCust.setFocus();
};

scwin.f_WinClose = function() {
    scwin.arrRtnVal[0] = "N/A";
    scwin.arrRtnVal[1] = ed_oldCust.getValue();
    scwin.arrRtnVal[2] = txt_oldCustnm.getValue();

    scwin.arrRtnVal[3] = ed_newCust.getValue();
    scwin.arrRtnVal[4] = txt_newCustnm.getValue();

    $c.win.closePopup(scwin.arrRtnVal);
};

scwin.f_PopUp = function(disGubun, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    switch (disGubun) {
        case "oldCustomer":
            udc_oldCust.ilCommonPopUp(scwin.callbackOldCustomer,
                ed_oldCust.getValue(),
                txt_oldCustnm.getValue(),
                pWinCloseTF,
                '6',
                'Customer',
                '140,300',
                null,
                null,
                '500',
                '500',
                null,
                null,
                null,
                pAllSearchTF,
                null,
                pNoDataCloseTF);
            break;
        case "newCustomer":
            udc_newCust.ilCommonPopUp(scwin.callbackNewCustomer,
                ed_newCust.getValue().trim(),
                txt_newCustnm.getValue(),
                pWinCloseTF,
                '6',
                'Customer',
                '140,300',
                null,
                null,
                '500',
                '500',
                null,
                null,
                null,
                pAllSearchTF,
                null,
                pNoDataCloseTF);
            break;
        default:
            break;
    }
};

scwin.callbackOldCustomer = function(rtnList) {
    if (typeof(rtnList) != "undefined") {
        if (rtnList[0] != "N/A") {
            $c.gus.cfSetReturnValue(rtnList, ed_oldCust, txt_oldCustnm);
        }
    }
};

scwin.callbackNewCustomer = function(rtnList) {
    if (typeof(rtnList) != "undefined") {
        if (rtnList[0] != "N/A") {
            $c.gus.cfSetReturnValue(rtnList, ed_newCust, txt_newCustnm);
        }
    }
};

scwin.ed_oldCust_onblur = function(e) {
    let strClntNo = ed_oldCust.getValue().trim();
    if (strClntNo.length > 0) {
        txt_oldCustnm.setValue("");
        scwin.f_PopUp("oldCustomer", "T", "F", "F");
    }
};

scwin.ed_newCust_onblur = function(e) {
    let strClntNo = ed_newCust.getValue().trim();
    if (strClntNo.length > 0) {
        txt_newCustnm.setValue("");
        scwin.f_PopUp("newCustomer", "T", "F", "F");
    }
};

scwin.btn_trigger2_onclick = function(e) {
    scwin.f_WinClose();
};
